class Solution:
    def addTwoNumbers(self, l1, l2):
        """
        :type l1: ListNode
        :type l2: ListNode
        :rtype: ListNode
        """
        head = ListNode(0)
        head.next = l1
        carry = 0

        while l1 and l2:  # 两个列表长度相同的部分
            s = l1.val + l2.val + carry
            val, carry = s % 10, s // 10
            l1.val = val
            prev, l1, l2 = l1, l1.next, l2.next

        l = l1 or l2  # 处理l1或l2余下的部分
        prev.next = l
        while l and carry:
            s = l.val + carry
            val, carry = s%10, s//10
            l.val = val
            prev, l = l, l.next

        if carry:  # 最后千万记得要处理进位
            prev.next = ListNode(1)

        return head.next

