class Solution:
    def longestCommonPrefix(self, strs):
        """
        :type strs: List[str]
        :rtype: str
        """
        if not strs:
            return ''
        if len(strs) == 1:
            return strs[0]
        cursor = -1
        ok = True
        while ok:
            cursor += 1
            if cursor == len(strs[0]): # 首个串已走完
                cursor -= 1
                break
            current_char = strs[0][cursor]
            for st in strs[1:]:
                if cursor == len(st) or st[cursor] != current_char: # 串走完或不匹配
                    cursor -= 1
                    ok = False
                    break
        return strs[0][:cursor+1]
